import React, { useState, useMemo } from 'react';
import { InspectionData } from '../types';
import SubscriptionLock from '../components/ui/SubscriptionLock';

interface PetroleumV2DashboardProps {
    stats: { total: number, passRate: number | string };
    startNewInspection: () => void;
    fetchHistory: () => void;
    isLoadingHistory: boolean;
    historyList: InspectionData[];
    onViewReport: (item: InspectionData) => void;
    onPrint: (item: InspectionData) => void;
    userRole?: string;
}

const PetroleumV2Dashboard: React.FC<PetroleumV2DashboardProps> = ({ stats, startNewInspection, fetchHistory, isLoadingHistory, historyList, onViewReport, onPrint, userRole }) => {
    const [searchTerm, setSearchTerm] = useState('');

    const displayList = useMemo(() => {
        let list = historyList;
        if (searchTerm.trim()) {
            const lowerSearch = searchTerm.toLowerCase();
            list = list.filter(item => 
                (item.truckNo && item.truckNo.toLowerCase().includes(lowerSearch)) ||
                (item.driverName && item.driverName.toLowerCase().includes(lowerSearch)) ||
                (item.inspectedBy && item.inspectedBy.toLowerCase().includes(lowerSearch))
            );
        } else {
            list = list.slice(0, 10);
        }
        return list;
    }, [historyList, searchTerm]);

    const handleShareWhatsApp = (item: InspectionData) => {
        const status = Number(item.rate) >= 4 ? '✅ PASSED' : Number(item.rate) === 3 ? '⚠️ WARNING' : '🛑 CRITICAL FAIL';
        const text = `*PETROLEUM V2 INSPECTION SUMMARY*\n\n*Vehicle:* ${item.truckNo}\n*Trailer:* ${item.trailerNo}\n*Inspector:* ${item.inspectedBy}\n*Date:* ${new Date(item.timestamp).toLocaleDateString()}\n\n*Result:* ${status} (${item.rate}/5)\n*Remarks:* ${item.remarks || 'None'}\n\n_Please log in to SafetyCheck Pro to download the full PDF report._`;
        window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
    };

    const isLocked = (window as any).isSubscriptionLocked || false;
    const canCreate = (userRole === 'Admin' || userRole === 'Inspector' || userRole === 'SuperAdmin') && !isLocked;

    return (
      <SubscriptionLock isLocked={isLocked}>
      <div className="max-w-6xl mx-auto space-y-8 animate-fadeIn">
          {/* Header Card - Professional Red Theme */}
          <div className="bg-white rounded-2xl p-8 shadow-sm border border-rose-100 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-64 h-64 bg-rose-50 rounded-full blur-3xl transform translate-x-1/2 -translate-y-1/2 group-hover:bg-rose-100 transition-colors"></div>

               <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                   <div>
                       <div className="flex items-center gap-3 mb-2">
                           <div className="p-2 bg-rose-100 text-rose-700 rounded-lg">
                               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                           </div>
                           <h2 className="text-2xl font-bold text-gray-800">Petroleum Inspection #2</h2>
                       </div>
                       <p className="text-gray-500 text-sm max-w-lg mb-6">Secondary safety audit for petroleum vehicles, focusing on compliance and tank integrity.</p>

                       <div className="flex flex-wrap gap-4">
                           {canCreate && (
                               <button onClick={startNewInspection} className="px-6 py-3 bg-rose-600 hover:bg-rose-700 text-white font-bold rounded-xl shadow-lg shadow-rose-200 transition transform hover:scale-105 active:scale-95 flex items-center gap-2">
                                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                                   Start New Inspection
                               </button>
                           )}
                           <button onClick={fetchHistory} className="px-6 py-3 bg-white border border-gray-200 text-gray-600 font-semibold rounded-xl hover:bg-gray-50 hover:text-rose-600 transition flex items-center gap-2">
                               <svg className={`w-5 h-5 ${isLoadingHistory ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                               Refresh Data
                           </button>
                       </div>
