import React, { useState, useEffect } from 'react';
import { SystemSettings, User, SubscriptionDetails } from '../../types';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
  activeModule: string;
  onSelectModule: (m: string) => void;
  settings: SystemSettings;
  user?: User; 
  onLogout?: () => void;
  onEditProfile?: () => void; 
  onLockedItemClick?: (featureName: string) => void;
  subscription?: SubscriptionDetails | null;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, onClose, activeModule, onSelectModule, settings, user, onLogout, onEditProfile, onLockedItemClick, subscription }) => {

    // Check if user is admin (Case Insensitive & Type Safe)
    const roleStr = user?.role ? String(user.role).toLowerCase() : '';
    const isAdmin = roleStr === 'admin' || roleStr === 'superadmin';

    const [logoError, setLogoError] = useState(false);

    // Reset error if logo url changes
    useEffect(() => {
        setLogoError(false);
    }, [settings.companyLogo]);

    const NavItem = ({ id, label, icon, subLabel, isLocked = false }: { id: string, label: string, icon: React.ReactNode, subLabel?: string, isLocked?: boolean }) => {
        const isActive = activeModule === id;
        const isProfile = id === 'profile'; 

        return (
            <button
                onClick={() => { 
                    if (isLocked && onLockedItemClick) {
                        onLockedItemClick(label);
                        onClose();
                    } else if (isProfile && onEditProfile) {
                        onEditProfile();
                        onClose();
                    } else {
                        onSelectModule(id); 
                        onClose(); 
                    }
                }}
                className={`w-full group relative flex items-center gap-3 px-3 py-2 rounded-lg transition-all duration-200 overflow-hidden
                    ${isActive 
                        ? 'bg-emerald-600 text-white shadow-md shadow-emerald-900/20' 
                        : isLocked 
                            ? 'text-slate-600 cursor-not-allowed opacity-70' 
                            : 'text-slate-400 hover:bg-slate-800 hover:text-white'
                    }
                `}
            >
                {isActive && (
                    <div className="absolute left-0 top-1.5 bottom-1.5 w-1 bg-white/40 rounded-r shadow-sm"></div>
                )}

                <span className={`relative z-10 transition-transform duration-300 shrink-0 ${isActive ? 'scale-105 text-white' : isLocked ? 'text-slate-600' : 'group-hover:text-white group-hover:scale-105'}`}>
                    {icon}
                </span>

                <div className="flex flex-col items-start relative z-10 text-left flex-1 min-w-0">
                    <div className="flex items-center justify-between w-full">
                        <span className={`text-sm font-semibold tracking-wide truncate leading-tight ${isActive ? 'text-white' : isLocked ? 'text-slate-600' : 'text-slate-300 group-hover:text-white'}`}>
                            {label}
                        </span>
                        {isLocked && (
                            <svg className="w-3 h-3 text-amber-600/50 ml-2 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                        )}
                    </div>
                    {subLabel && (
                        <span className={`text-[10px] leading-tight ${isActive ? 'text-emerald-100' : 'text-slate-500'}`}>
                            {subLabel}
                        </span>
                    )}
                </div>
            </button>
        );
    };

    return (
        <>
            {/* Mobile Backdrop */}
            {isOpen && (
                <div 
                    className="fixed inset-0 z-[55] bg-slate-900/60 backdrop-blur-sm lg:hidden transition-opacity cursor-pointer"
                    onClick={onClose}
                ></div>
            )}

            <aside className={`fixed inset-y-0 left-0 z-[60] w-64 bg-slate-900 text-white transform transition-transform duration-300 ease-out ${isOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 border-r border-slate-800 flex flex-col shadow-2xl`}>
                 {/* Header */}
                 <div className="px-4 py-5 border-b border-slate-800 bg-black/20 shrink-0">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className="w-9 h-9 rounded-lg bg-white flex items-center justify-center text-emerald-900 shadow-lg shrink-0 overflow-hidden p-1">
                                    {settings.companyLogo && !logoError ? (
                                        <img 
                                            src={settings.companyLogo} 
                                            alt="Logo" 
                                            className="w-full h-full object-contain" 
                                            onError={() => setLogoError(true)}
                                        />
                                    ) : (
                                        <svg className="w-5 h-5 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"></path></svg>
                                    )}
                                </div>
                                <div className="min-w-0 flex flex-col justify-center">
                                    <h1 className="text-sm font-black tracking-tight text-white leading-tight truncate">
                                        {settings.companyName || 'SafetyPro'}
                                    </h1>
                                    <span className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest truncate block">
                                        System Active
                                    </span>
                                </div>
                            </div>
                            <button onClick={onClose} className="lg:hidden text-slate-400 hover:text-white transition-colors p-1.5 hover:bg-white/10 rounded-lg">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                            </button>
                        </div>
                </div>

                {/* Navigation - Main Scrollable Area */}
                {/* flex-1 ensures it takes available height, pushing the footer down but allowing scrolling if items overflow */}
                <div className="flex-1 overflow-y-auto scrollbar-hide px-3 py-4 space-y-0.5">
                     <div className="mb-3">
                        <NavItem 
