interface GeneralDashboardProps {
    stats: { total: number, passRate: number | string };
    startNewInspection: () => void;
    fetchHistory: () => void;
    isLoadingHistory: boolean;
    historyList: InspectionData[];
    onViewReport: (item: InspectionData) => void;
    onPrint: (item: InspectionData) => void;
    userRole?: string; // Passed from App
}

const GeneralDashboard: React.FC<GeneralDashboardProps> = ({ stats, startNewInspection, fetchHistory, isLoadingHistory, historyList, onViewReport, onPrint, userRole }) => {
    const [searchTerm, setSearchTerm] = useState('');

    const displayList = useMemo(() => {
        let list = historyList;

        if (searchTerm.trim()) {
            const lowerSearch = searchTerm.toLowerCase();
            list = list.filter(item => 
                (item.truckNo && item.truckNo.toLowerCase().includes(lowerSearch)) ||
                (item.driverName && item.driverName.toLowerCase().includes(lowerSearch)) ||
                (item.inspectedBy && item.inspectedBy.toLowerCase().includes(lowerSearch))
            );
        } else {
            // Only show top 10 if not searching
            list = list.slice(0, 10);
        }
        return list;
    }, [historyList, searchTerm]);

    const handleShareWhatsApp = (item: InspectionData) => {
        const status = Number(item.rate) >= 4 ? '✅ PASSED' : Number(item.rate) === 3 ? '⚠️ WARNING' : '🛑 CRITICAL FAIL';
        const text = `*INSPECTION REPORT SUMMARY*\n\n*Vehicle:* ${item.truckNo}\n*Trailer:* ${item.trailerNo}\n*Inspector:* ${item.inspectedBy}\n*Date:* ${new Date(item.timestamp).toLocaleDateString()}\n\n*Result:* ${status} (${item.rate}/5)\n*Remarks:* ${item.remarks || 'None'}\n\n_Please log in to SafetyCheck Pro to download the full PDF report._`;
        window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
    };

