interface SupportViewProps {
    appScriptUrl: string;
    currentUser: User | null;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
}

const SupportView: React.FC<SupportViewProps> = ({ appScriptUrl, currentUser, showToast }) => {
    const [ticketType, setTicketType] = useState<'Issue' | 'Feature' | 'Other'>('Issue');
    const [subject, setSubject] = useState('');
    const [description, setDescription] = useState('');
    const [priority, setPriority] = useState('Medium');
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!appScriptUrl) {
            showToast("System offline. Please check settings.", "error");
            return;
        }

        setIsSubmitting(true);
        try {
            const payload = {
                action: 'submit_support_ticket',
                type: ticketType,
                subject,
                description,
                priority,
                user: currentUser?.name || 'Anonymous',
                email: currentUser?.username || 'N/A', // Using username as ID/Email proxy
                role: currentUser?.role || 'N/A'
            };

            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload),
                mode: 'no-cors'
            });

            // Since no-cors returns opaque response, we assume success if no error thrown
            showToast("Ticket submitted successfully!", "success");
            setSubject('');
            setDescription('');
            setPriority('Medium');
        } catch (error) {
            showToast("Failed to submit ticket.", "error");
        } finally {
