interface SettingsViewProps {
    settings: SystemSettings;
    setSettings: React.Dispatch<React.SetStateAction<SystemSettings>>;
    appScriptUrl: string;
    setAppScriptUrl: (url: string) => void;
    handleSaveSettings: () => void;
    isSavingSettings: boolean;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    user?: User | null; // Passed to check roles
}

const SettingsView: React.FC<SettingsViewProps> = ({ 
    settings, setSettings, appScriptUrl, setAppScriptUrl, handleSaveSettings, isSavingSettings, showToast, user 
}) => {
    const [isCopying, setIsCopying] = useState(false);
    const [showEmailHelp, setShowEmailHelp] = useState(false);
    const [isExtending, setIsExtending] = useState(false);
    const [logoError, setLogoError] = useState(false);

    useEffect(() => {
        setLogoError(false);
    }, [settings.companyLogo]);

    // Permission Logic
    const isSuperAdmin = user?.role === 'SuperAdmin';
    const canEditCompanySettings = isSuperAdmin || user?.role === 'Admin';
    const canEditSystemConfig = isSuperAdmin; // Only SuperAdmin changes DB

    const compressImage = (file: File, callback: (base64: string) => void) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            const img = new Image();
            img.onload = () => {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');

                // Professional resizing logic
                const maxWidth = 300; 
                const maxHeight = 150;
                let width = img.width;
                let height = img.height;

                if (width > height) {
                    if (width > maxWidth) {
                        height *= maxWidth / width;
                        width = maxWidth;
                    }
                } else {
                    if (height > maxHeight) {
                        width *= maxHeight / height;
                        height = maxHeight;
                    }
                }

                canvas.width = width;
                canvas.height = height;

                if (ctx) {
                    ctx.fillStyle = "#FFFFFF";
                    ctx.fillRect(0, 0, width, height);
                    ctx.drawImage(img, 0, 0, width, height);
                    const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                    callback(dataUrl);
                }
            };
            img.src = e.target?.result as string;
        };
        reader.readAsDataURL(file);
    };

    const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!canEditCompanySettings) return;
        const file = e.target.files?.[0];
        if (file) {
          showToast("Compressing logo...", 'info');
          compressImage(file, (base64) => {
             setSettings(s => ({ ...s, companyLogo: base64 }));
