                method: 'POST',
                body: JSON.stringify({
                    action: 'extend_subscription',
                    days: days
                })
            });

            const text = await response.text();
            let result;
            try {
                result = JSON.parse(text);
            } catch (e) {
                console.error("Non-JSON response received:", text);
                showToast("Server Error: Your backend script might be crashing. Please update the code below.", 'error');
                setIsExtending(false);
                return;
            }

            if (result.status === 'success') {
                showToast(`License extended by ${days} days. Refreshing...`, 'success');
