    );
};

export default SupportView;

export enum InspectionStatus {
  GOOD = 'Good',
  BAD = 'Bad',
  ATTENTION = 'Needs Attention',
  NIL = 'Nil'
}

export interface UserPreferences {
    emailNotifications: boolean;
    notifyGeneral: boolean;
    notifyPetroleum: boolean;
    notifyPetroleumV2: boolean;
    notifyAcid: boolean;
}

export interface User {
  username: string;
  name: string;
  role: 'SuperAdmin' | 'Admin' | 'Inspector' | 'Operations' | 'Maintenance' | 'Other';
  position?: string;
  lastLogin?: string;
  preferences?: UserPreferences;
}

export interface SubscriptionDetails {
    status: 'Active' | 'Expired' | 'Trial';
    plan: string;
    expiryDate: string;
    daysRemaining: number;
}

export interface AppNotification {
    id: string;
    title: string;
    message: string;
    type: 'critical' | 'warning' | 'info' | 'success';
    timestamp: string;
    read: boolean;
    module?: string; // To link to specific dashboard if needed
    recordId?: string; // To identify specific inspection

    // SystemNotification Sheet Specifics
    recipientId?: string;
    actionLink?: string; // e.g., "view:users", "view:settings"
    isServerEvent?: boolean; // True if it comes from SystemNotification sheet
}

export interface TicketComment {
    user: string;
    role: string;
    message: string;
    timestamp: string;
}

export interface SupportTicket {
    ticketId: string;
    type: string;
    subject: string;
    description: string;
    priority: string;
    user: string; // Name
    email: string; // Username/Email ID
