    timestamp: string;
    status: 'Open' | 'In Progress' | 'Resolved' | 'Closed';
    comments: TicketComment[];
}

export interface InspectionItemConfig {
  id: string;
  label: string;
  category: string;
}

export interface SystemSettings {
    companyName: string;
    managerEmail: string;
    companyLogo?: string; // Base64 string for the custom logo
    mobileApkLink?: string; // Link to download APK
    webAppUrl?: string; // Link to web browser version
}

export interface ValidationLists {
    trucks: string[];
    trailers: string[];
    drivers: string[];
    inspectors: string[];
    locations: string[];
    positions: string[]; // Added Positions
}

export interface InspectionData {
  // Metadata
  timestamp: string;

  // Text Fields
  truckNo: string;
  trailerNo: string;
  inspectedBy: string;
  driverName: string;
  location: string;
