                                                ${u.role === 'SuperAdmin' ? 'bg-black text-white' : 
                                                  u.role === 'Admin' ? 'bg-purple-100 text-purple-700' : 
                                                  u.role === 'Operations' ? 'bg-blue-100 text-blue-700' :
                                                  u.role === 'Maintenance' ? 'bg-orange-100 text-orange-700' :
