import React, { useState, useEffect } from 'react';
import { SystemSettings, User } from '../types';
import { BACKEND_SCRIPT_TEMPLATE } from '../constants';

interface SettingsViewProps {
    settings: SystemSettings;
    setSettings: React.Dispatch<React.SetStateAction<SystemSettings>>;
    appScriptUrl: string;
    setAppScriptUrl: (url: string) => void;
    handleSaveSettings: () => void;
    isSavingSettings: boolean;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    user?: User | null; // Passed to check roles
}

const SettingsView: React.FC<SettingsViewProps> = ({ 
    settings, setSettings, appScriptUrl, setAppScriptUrl, handleSaveSettings, isSavingSettings, showToast, user 
}) => {
    const [isCopying, setIsCopying] = useState(false);
    const [showEmailHelp, setShowEmailHelp] = useState(false);
    const [isExtending, setIsExtending] = useState(false);
    const [logoError, setLogoError] = useState(false);

    useEffect(() => {
        setLogoError(false);
    }, [settings.companyLogo]);

    // Permission Logic
    const isSuperAdmin = user?.role === 'SuperAdmin';
    const canEditCompanySettings = isSuperAdmin || user?.role === 'Admin';
    const canEditSystemConfig = isSuperAdmin; // Only SuperAdmin changes DB

    const compressImage = (file: File, callback: (base64: string) => void) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            const img = new Image();
            img.onload = () => {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');

                // Professional resizing logic
                const maxWidth = 300; 
                const maxHeight = 150;
                let width = img.width;
                let height = img.height;

                if (width > height) {
                    if (width > maxWidth) {
                        height *= maxWidth / width;
                        width = maxWidth;
                    }
                } else {
                    if (height > maxHeight) {
                        width *= maxHeight / height;
                        height = maxHeight;
                    }
                }

                canvas.width = width;
                canvas.height = height;

                if (ctx) {
                    ctx.fillStyle = "#FFFFFF";
                    ctx.fillRect(0, 0, width, height);
                    ctx.drawImage(img, 0, 0, width, height);
                    const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                    callback(dataUrl);
                }
            };
            img.src = e.target?.result as string;
        };
        reader.readAsDataURL(file);
    };

    const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!canEditCompanySettings) return;
        const file = e.target.files?.[0];
        if (file) {
          showToast("Compressing logo...", 'info');
          compressImage(file, (base64) => {
             setSettings(s => ({ ...s, companyLogo: base64 }));
             showToast("Logo processed. Click 'Save Configuration' to persist.", 'success');
          });
        }
    };

    const copyScriptToClipboard = () => {
        navigator.clipboard.writeText(BACKEND_SCRIPT_TEMPLATE);
        setIsCopying(true);
        showToast("Code copied to clipboard!", 'success');
        setTimeout(() => setIsCopying(false), 2000);
    };

    const copyToClipboard = (text: string, label: string) => {
        if (!text) return;
        navigator.clipboard.writeText(text).then(() => {
            showToast(`${label} copied!`, 'success');
        }).catch(() => showToast("Failed to copy", 'error'));
    };

    const handleCombinedShare = async () => {
        const company = settings.companyName || 'SafetyCheck Pro';
        const webUrl = settings.webAppUrl || 'Not configured';
        const apkLink = settings.mobileApkLink || 'Not configured';

        const title = `${company} - App Access`;
        const text = `🚀 SYSTEM ACCESS DETAILS\n\nOrganization: ${company}\n\nHere are the links to access the Inspection System:\n\n📱 DOWNLOAD MOBILE APP (Android):\n${apkLink}\n\n💻 ACCESS WEB PORTAL:\n${webUrl}\n\nPlease save these links for future use.`;

        // IMPORTANT: We do NOT pass 'url' here. Passing 'url' combined with 'text' often causes
        // mobile share sheets to ignore the text block and only share the URL.
        // By passing only 'text', we ensure the full message (with both links) is shared.
        if (navigator.share) {
            try {
                await navigator.share({
                    title: title,
                    text: text
                });
                showToast("System details shared successfully!", 'success');
            } catch (err) {
                // Fallback to clipboard if share fails/cancelled
                copyToClipboard(text, "Access Details");
            }
        } else {
            copyToClipboard(text, "Access Details");
        }
    };

    const handleExtendSubscription = async (days: number) => {
        if (!isSuperAdmin) return;
        setIsExtending(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'extend_subscription',
                    days: days
                })
            });

            const text = await response.text();
            let result;
            try {
                result = JSON.parse(text);
            } catch (e) {
                console.error("Non-JSON response received:", text);
                showToast("Server Error: Your backend script might be crashing. Please update the code below.", 'error');
                setIsExtending(false);
                return;
            }

            if (result.status === 'success') {
                showToast(`License extended by ${days} days. Refreshing...`, 'success');
                // Force reload to update state
                setTimeout(() => window.location.reload(), 1500);
            } else {
                showToast(result.message || "Failed to extend license.", 'error');
            }
        } catch (e) {
            console.error("Extension failed:", e);
            showToast("Connection failed. Ensure script is deployed.", 'error');
        } finally {
            setIsExtending(false);
        }
    };

