                    <div className="relative">
                        <pre className="bg-slate-950 p-4 rounded-lg overflow-x-auto text-[10px] sm:text-xs font-mono text-green-400 border border-slate-800 h-64 overflow-y-auto">
                            {BACKEND_SCRIPT_TEMPLATE}
                        </pre>
                    </div>
                 </div>
             )}
        </div>
    );
}

export default SettingsView;

import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    // User type extended with password for sharing logic
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    // View State: 'list' or 'form'
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    // Form State
    const [formData, setFormData] = useState<{
        name: string;
        username: string;
        password: string;
        role: 'SuperAdmin' | 'Admin' | 'Inspector' | 'Operations' | 'Maintenance' | 'Other';
        position: string;
    }>({
        name: '',
        username: '',
        password: '',
        role: 'Inspector',
        position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Only SuperAdmin can create other SuperAdmins
    const isSuperAdmin = currentUser.role === 'SuperAdmin';

    useEffect(() => {
        fetchUsers();
    }, []);

    const fetchUsers = async () => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'get_users' })
            });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                let fetchedUsers = result.users;

                // SECURITY: Hide SuperAdmins from regular Admins
                if (!isSuperAdmin) {
                    fetchedUsers = fetchedUsers.filter((u: User) => u.role !== 'SuperAdmin');
                }

                setUsers(fetchedUsers);
            }
        } catch (e) {
            console.error(e);
            showToast("Failed to load users", 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Are you sure you want to remove user "${username}"?`)) return;

        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'delete_user', username })
            });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else {
                showToast(result.message || "Failed to delete user", 'error');
            }
        } catch (e) {
            showToast("Connection failed", 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleEdit = (user: User) => {
        setFormData({
            name: user.name,
            username: user.username,
            role: user.role,
            position: user.position || '',
            password: '' // Leave empty for edit
        });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!formData.name || !formData.username) {
            showToast("Please fill in required fields.", 'error');
            return;
        }

        if (!isEditing && !formData.password) {
             showToast("Password is required for new users.", 'error');
             return;
        }

        setIsSubmitting(true);

        try {
            // Find current user's existing preferences to preserve them, OR set default
            const existingUser = users.find(u => u.username === originalUsername);
            let prefs = existingUser?.preferences || {
                emailNotifications: true,
                notifyGeneral: true,
                notifyPetroleum: true,
                notifyPetroleumV2: true,
                notifyAcid: true,
                mustChangePassword: false
            };

            // If creating new user, OR changing password for existing user, force password change on next login
            if (!isEditing || (formData.password && formData.password.trim() !== '')) {
                prefs = { ...prefs, mustChangePassword: true };
            }

            const payload: any = {
                action: isEditing ? 'update_user' : 'register_user',
                ...formData,
                preferences: prefs
            };

            if (isEditing) {
                payload.originalUsername = originalUsername;
            }

            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload)
            });
            const result = await response.json();

            if (result.status === 'success') {
                const msg = isEditing 
                    ? (formData.password ? "User updated. They must change password on next login." : "User updated successfully")
                    : "User created. They must change password on first login.";

                showToast(msg, 'success');
                setViewMode('list');
                setFormData({ name: '', username: '', password: '', role: 'Inspector', position: '' });
                setIsEditing(false);
                fetchUsers();
            } else {
                showToast(result.message || "Operation failed", 'error');
            }
        } catch (e) {
            showToast("Connection failed", 'error');
        } finally {
            setIsSubmitting(false);
        }
    };

    // Robust Fallback Copy Mechanism
    const fallbackCopyTextToClipboard = (text: string) => {
        const textArea = document.createElement("textarea");
        textArea.value = text;

        // Avoid scrolling to bottom
        textArea.style.top = "0";
        textArea.style.left = "0";
        textArea.style.position = "fixed";
        textArea.style.opacity = "0";

        document.body.appendChild(textArea);
        textArea.focus();
        textArea.select();

        try {
            const successful = document.execCommand('copy');
            if (successful) {
                showToast("Details copied to clipboard (Fallback)", 'success');
            } else {
                showToast("Unable to copy details. Please copy manually.", 'error');
            }
        } catch (err) {
            showToast("Unable to copy details. Please copy manually.", 'error');
        }

        document.body.removeChild(textArea);
    };

    const handleShareUser = async (user: User & {password?: string}) => {
        const companyName = settings?.companyName || 'SafetyCheck Pro';
        const webUrl = settings?.webAppUrl || window.location.origin + window.location.pathname;
        const apkUrl = settings?.mobileApkLink || 'Contact Admin for APK';

        const title = "System Access Credentials";
        const text = `
${companyName.toUpperCase()} - ACCESS CREDENTIALS
----------------------------------
Here are your login details for the digital inspection system.

Name: ${user.name}
Role: ${user.role}
${user.position ? `Position: ${user.position}` : ''}

LOGIN DETAILS:
Username: ${user.username}
Password: ${user.password || '****'} (Change on first login)

ACCESS LINKS:
💻 Web Portal:
${webUrl}

📱 Android App:
${apkUrl}

Please keep these credentials secure.
----------------------------------
`.trim();

        if (navigator.share) {
            try {
                // Pass text ONLY to ensure consistent behavior across platforms (avoiding URL-only shares)
                await navigator.share({
                    title: title,
                    text: text
                });
                showToast("Credentials shared successfully via System", 'success');
            } catch (err) {
                // User cancelled or API failed
                // Attempt Clipboard Fallback
                try {
                    await navigator.clipboard.writeText(text);
                    showToast("Share cancelled. Details copied to clipboard.", 'info');
                } catch (clipboardErr) {
                    fallbackCopyTextToClipboard(text);
                }
            }
        } else {
            // Fallback for browsers without share support
            try {
                await navigator.clipboard.writeText(text);
                showToast("Credentials copied to clipboard!", 'success');
            } catch (err) {
                fallbackCopyTextToClipboard(text);
            }
        }
    };

    // Access Control: Must be Admin or SuperAdmin
    const canManage = currentUser.role && (currentUser.role.toLowerCase() === 'admin' || currentUser.role === 'superadmin');

    if (!canManage) {
        return <div className="p-8 text-center text-red-600 font-bold">Access Denied. Admin Privileges Required.</div>;
    }

    // --- FORM VIEW (CREATE & EDIT) ---
    if (viewMode === 'form') {
        return (
            <div className="max-w-lg mx-auto animate-fadeIn py-4 px-2 sm:px-0">
                <button 
                    onClick={() => setViewMode('list')}
                    className="mb-4 flex items-center gap-2 text-gray-500 hover:text-gray-800 transition-colors text-xs font-bold uppercase tracking-wider"
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"></path></svg>
                    Back to List
                </button>

                <div className="bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden">
                    <div className="bg-slate-50 px-6 py-4 border-b border-gray-100 flex items-center justify-between">
                        <h2 className="text-lg font-black text-slate-800 tracking-tight">
                            {isEditing ? 'Edit User Details' : 'Create New User'}
                        </h2>
                        <div className="w-8 h-8 bg-white rounded-lg shadow-sm flex items-center justify-center text-blue-600 border border-gray-100">
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        </div>
                    </div>

                    <div className="p-6">
                        <form onSubmit={handleSubmit} className="space-y-4">

                            {/* Full Name */}
                            <div className="space-y-1">
                                <AutocompleteInput
                                    label="Full Name"
                                    value={formData.name}
                                    onChange={v => setFormData({...formData, name: v})}
                                    options={validationLists.inspectors} 
                                    isTitleCase={true}
                                    placeholder="e.g. John Doe"
                                />
                            </div>

                            {/* Position & Role (Side-by-Side) */}
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <AutocompleteInput
                                        label="Position"
                                        value={formData.position}
                                        onChange={v => setFormData({...formData, position: v})}
                                        options={validationLists.positions} 
                                        isTitleCase={true}
                                        placeholder="Job Title"
                                    />
                                </div>
                                <div>
                                    <div className="flex justify-between items-center mb-1.5">
                                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wide">System Role</label>
                                        {!isSuperAdmin && (
                                            <span className="text-[9px] text-amber-600 font-medium flex items-center gap-1 bg-amber-50 px-1.5 py-0.5 rounded border border-amber-100">
                                                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                                                Restricted
                                            </span>
                                        )}
                                    </div>
                                    <select 
                                        className="w-full p-3.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50 text-sm font-medium transition-colors text-gray-800"
                                        value={formData.role}
                                        onChange={e => setFormData({...formData, role: e.target.value as any})}
                                    >
                                        <option value="Inspector">Inspector</option>
                                        <option value="Operations">Operations</option>
                                        <option value="Maintenance">Maintenance</option>
                                        <option value="Other">Other</option>
                                        <option value="Admin">Admin</option>
                                        {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                    </select>
                                </div>
                            </div>

                            {/* Username & Password (Side-by-Side) */}
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 tracking-wide">Username</label>
                                    <input 
                                        type="text" required 
                                        className="w-full p-3.5 border rounded-lg outline-none font-medium transition-all text-sm bg-gray-50 border-gray-200 text-gray-800 focus:ring-2 focus:ring-blue-500"
                                        value={formData.username}
                                        onChange={e => setFormData({...formData, username: e.target.value})}
                                        placeholder="jdoe"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 tracking-wide">
                                        Password {isEditing && <span className="text-gray-400 font-normal normal-case">(Optional)</span>}
                                    </label>
                                    <input 
                                        type="password" 
                                        required={!isEditing}
                                        className="w-full p-3.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50 text-gray-800 placeholder-gray-400 font-medium transition-all text-sm"
                                        value={formData.password}
                                        onChange={e => setFormData({...formData, password: e.target.value})}
                                        placeholder={isEditing ? "Leave blank to keep current" : "••••"}
                                    />
                                </div>
                            </div>

                            <div className="p-3 bg-amber-50 rounded-lg border border-amber-100 flex items-start gap-2">
                                <svg className="w-4 h-4 text-amber-600 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                <p className="text-[10px] text-amber-800">
                                    Setting a password will prompt the user to change it upon their next login for security.
                                </p>
                            </div>

                            <div className="pt-4 flex gap-3">
                                <button 
                                    type="button" 
                                    onClick={() => setViewMode('list')}
                                    className="flex-1 py-3 bg-white border border-gray-300 hover:bg-gray-50 text-gray-700 font-bold rounded-xl transition text-sm"
                                >
                                    Cancel
                                </button>
                                <button 
                                    type="submit"
                                    disabled={isSubmitting}
                                    className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-md transition disabled:bg-blue-400 text-sm flex items-center justify-center gap-2"
                                >
                                    {isSubmitting ? 'Saving...' : isEditing ? 'Update User' : 'Create User'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        );
    }

    // --- LIST VIEW ---
    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-3">
                    <span className="p-2 bg-purple-100 text-purple-700 rounded-lg">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
                    </span>
                    User Management
                </h2>
                <div className="flex gap-3 w-full sm:w-auto">
                     <button 
                        onClick={fetchUsers} 
                        className="flex-1 sm:flex-none justify-center px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 flex items-center gap-2"
                    >
                        <svg className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                        Refresh
                    </button>
                    <button 
                        onClick={() => {
                            setFormData({ name: '', username: '', password: '', role: 'Inspector', position: '' });
                            setIsEditing(false);
                            setViewMode('form');
                        }}
                        className="flex-1 sm:flex-none justify-center px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-lg shadow-md flex items-center gap-2 transition"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        Add User
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm whitespace-nowrap">
                        <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase border-b border-gray-200">
                            <tr>
                                <th className="px-4 py-3">Name / Position</th>
                                <th className="px-4 py-3">Username</th>
                                <th className="px-4 py-3">Role</th>
                                <th className="px-4 py-3">Last Login</th>
                                <th className="px-4 py-3 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {users.length === 0 ? (
                                <tr><td colSpan={5} className="p-8 text-center text-gray-500">{isLoading ? 'Loading users...' : 'No users found.'}</td></tr>
                            ) : (
                                users.map((u, i) => (
                                    <tr key={i} className="hover:bg-gray-50">
                                        <td className="px-4 py-3">
                                            <div className="font-bold text-gray-900">{u.name}</div>
                                            <div className="text-xs text-gray-500">{u.position}</div>
                                        </td>
                                        <td className="px-4 py-3 font-mono text-gray-600">{u.username}</td>
                                        <td className="px-4 py-3">
                                            <span className={`px-2 py-1 rounded text-xs font-bold 
                                                ${u.role === 'SuperAdmin' ? 'bg-black text-white' : 
                                                  u.role === 'Admin' ? 'bg-purple-100 text-purple-700' : 
                                                  u.role === 'Operations' ? 'bg-blue-100 text-blue-700' :
                                                  u.role === 'Maintenance' ? 'bg-orange-100 text-orange-700' :
                                                  'bg-green-100 text-green-700'}`}>
                                                {u.role}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3 text-gray-500 text-xs">
                                            {u.lastLogin ? new Date(u.lastLogin).toLocaleDateString() : 'Never'}
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            {u.username !== currentUser.username && (
                                                <div className="flex justify-end gap-2">
                                                    {/* Native Share - Increased Hit Area */}
                                                    <button 
                                                        onClick={() => handleShareUser(u)}
                                                        title="Share Access Credentials & Links"
                                                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded border border-transparent hover:border-indigo-200 transition-colors"
                                                    >
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"></path></svg>
                                                    </button>

                                                    {/* Edit */}
                                                    <button 
                                                        onClick={() => handleEdit(u)}
                                                        title="Edit User"
                                                        className="p-2 text-blue-600 hover:bg-blue-50 rounded border border-transparent hover:border-blue-200 transition-colors"
                                                    >
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                                                    </button>

                                                    {/* Delete */}
                                                    <button 
                                                        onClick={() => handleDelete(u.username)}
                                                        title="Delete User"
                                                        className="p-2 text-red-600 hover:bg-red-50 rounded border border-transparent hover:border-red-200 transition-colors"
                                                    >
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                                                    </button>
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default UserManagementView;

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import Sidebar from './components/layout/Sidebar';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';

// Reports (Only for Preview now)
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  // --- CORE HOOKS ---
  const { currentUser, setCurrentUser, handleLogin, handleLogout } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();

  // Subscription Hook - The heart of the new security model
  const { subscription, isLocked, refreshSubscription } = useSubscription(appScriptUrl, currentUser);

  // Global hack to pass lock state to deep components without prop drilling hell immediately
  // Ideally this should be context, but for quick refactor:
  if (typeof window !== 'undefined') {
      (window as any).isSubscriptionLocked = isLocked;
  }

  // Navigation State
  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');

  // UI State
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [upgradeFeature, setUpgradeFeature] = useState<string | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

  // --- DATA HOOKS ---
  const { historyList, isLoadingHistory, isBackgroundFetching, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule);

  const showToast = (message: string, type: 'success' | 'error' | 'info') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  const { submissionStatus, setSubmissionStatus, offlineQueue, isSyncing, syncOfflineQueue, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  const { notifications, fetchNotifications, handleMarkNotificationRead, handleDismissNotification, handleGlobalAcknowledge, handleClearAllNotifications } = useNotifications(appScriptUrl, currentUser, showToast);

  // --- LOCAL STATE ---
  const [isStartModalOpen, setIsStartModalOpen] = useState(false);
  const [targetModuleForStart, setTargetModuleForStart] = useState<string | null>(null);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);

  // Form Init State
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  // Access Control Effect
  useEffect(() => {
      if (currentUser) {
          // Normalize role check
          const role = currentUser.role || '';
          const isAdmin = role === 'Admin' || role === 'SuperAdmin';

          if (!isAdmin && (activeModule === 'settings' || activeModule === 'users')) {
              showToast("Access Restricted to Admins.", 'error');
              setActiveModule('overview');
          }
      }
  }, [activeModule, currentUser]);

  // Data Fetching Effect
  useEffect(() => {
    if (!currentUser || !appScriptUrl) return;

    if (navigator.onLine) {
        fetchNotifications();
        if (offlineQueue.length > 0) syncOfflineQueue();
    }

    // Fetch history when entering a module dashboard
    if (viewMode === 'dashboard' && ['general', 'petroleum', 'petroleum_v2', 'acid'].includes(activeModule)) {
       fetchHistory(false);
    }
  }, [activeModule, viewMode, currentUser]);


  // --- DRAFT LOGIC ---
  const getDraftKey = (module: string) => `sc_draft_${module}`;
  const hasDraft = (module: string) => !!localStorage.getItem(getDraftKey(module));

  const loadDraft = (module: string) => {
      const draft = localStorage.getItem(getDraftKey(module));
      if (draft) {
          try { return JSON.parse(draft); } catch(e) { return null; }
      }
      return null;
  };

  const clearDraft = (module: string) => localStorage.removeItem(getDraftKey(module));

  const handleInitiateStartInspection = (module: string) => {
      // Prevent start if locked
      if (isLocked) {
          showToast("Subscription Expired. Cannot start inspection.", 'error');
          return;
      }

      if (hasDraft(module)) {
          setTargetModuleForStart(module);
          setIsStartModalOpen(true);
      } else {
          startFreshInspection(module);
      }
  };

  const startFreshInspection = (module: string) => {
      clearDraft(module); 
      setFormInitialData({ 
          ...INITIAL_DATA, 
          timestamp: new Date().toISOString(),
          inspectedBy: currentUser?.name || '' 
      });
      setViewMode('form');
  };

  const resumeDraftInspection = (module: string) => {
      const draft = loadDraft(module);
      if (draft) {
          setFormInitialData(draft);
          setViewMode('form');
          showToast("Draft resumed.", 'info');
      } else {
          showToast("Failed to load draft. Starting new.", 'error');
          startFreshInspection(module);
      }
  };

  const handleExitForm = (savedData?: InspectionData) => {
      if (savedData) {
          localStorage.setItem(getDraftKey(activeModule), JSON.stringify(savedData));
          showToast("Draft saved successfully.", 'success');
      }
      setViewMode('dashboard');
  };

  // --- SUBMISSION LOGIC ---
  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (currentUser?.role && !['Admin', 'Inspector', 'SuperAdmin'].includes(currentUser.role)) {
        showToast("Access Denied: View Only Account.", 'error');
        return;
    }

    if (!appScriptUrl) {
        showToast("System Not Connected. Please configure Settings.", 'error');
        setActiveModule('settings');
        return;
    }

    setSubmissionStatus('submitting');

    const recordId = crypto.randomUUID();
    let targetSheet = "General";
    let targetHeaders = SHEET_HEADERS;

    // Prepare Data Payload for Server-Side PDF Generation
    let reportItems: { category: string, label: string, status: string }[] = [];
    let reportTitle = "General Inspection Report";

    if (activeModule === 'petroleum') {
        targetSheet = "Petroleum";
        targetHeaders = PETROLEUM_HEADERS;
        reportTitle = "Petroleum Tanker Inspection";
        reportItems = PETROLEUM_INSPECTION_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    } else if (activeModule === 'petroleum_v2') {
        targetSheet = "Petroleum_V2";
        targetHeaders = PETROLEUM_V2_HEADERS;
        reportTitle = "Petroleum Tanker Inspection V2";
        reportItems = PETROLEUM_V2_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    } else if (activeModule === 'acid') {
        targetSheet = "Acid";
        targetHeaders = ACID_HEADERS;
        reportTitle = "Acid Tanker Inspection";
        reportItems = ACID_INSPECTION_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    } else {
        // General
        reportItems = INSPECTION_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    }

    const reportData = {
        title: reportTitle,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard || 'N/A',
        driverName: formData.driverName,
        inspectedBy: formData.inspectedBy,
        location: formData.location,
        odometer: formData.odometer,
        timestamp: formData.timestamp,
        remarks: formData.remarks,
        rate: formData.rate,
        items: reportItems,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const rowData = targetHeaders.map(header => {
        if (header === 'id') return recordId;
        const val = (formData as any)[header];
        return (val === null || val === undefined) ? "" : val;
    });

    const payload = {
        sheet: targetSheet,
        action: "create",
        row: rowData,
        headers: targetHeaders,
        id: recordId,
        reportData: reportData
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        clearDraft(activeModule);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
             startFreshInspection(activeModule); 
             setViewMode('dashboard');
             setSubmissionStatus('idle');
             showToast("Offline Mode: Report Saved. Will sync when online.", 'info');
        }, 2000);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors', 
            headers: { 'Content-Type': 'text/plain' }
        });

        clearDraft(activeModule);
        setSubmissionStatus('success');

        setTimeout(() => {
             startFreshInspection(activeModule); 
             setViewMode('dashboard');
             setSubmissionStatus('idle');
             fetchHistory(true); 
             fetchNotifications();
             showToast("Inspection Submitted & Email Sent!", 'success');
        }, 2500);

    } catch (error) {
        console.error("Submission Error", error);
        addToQueue(payload);
        clearDraft(activeModule); 
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
             startFreshInspection(activeModule); 
             setViewMode('dashboard');
             setSubmissionStatus('idle');
             showToast("Network Error: Report queued for sync.", 'info');
        }, 2500);
    }
  };

  const handlePrint = () => window.print();
  const handleQuickPrint = (item: InspectionData) => {
      setSelectedReportData(item);
      setTimeout(() => window.print(), 500);
  };
  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  // --- RENDER ---
  if (!currentUser) {
      return (
          <LoginView 
            onLogin={handleLogin} 
            appScriptUrl={appScriptUrl}
            setAppScriptUrl={setAppScriptUrl}
            settings={settings}
          />
      );
  }

  const canAcknowledge = ['Admin', 'Maintenance', 'Inspector', 'SuperAdmin'].includes(currentUser.role || '');

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <InspectionStartModal 
          isOpen={isStartModalOpen}
          onClose={() => setIsStartModalOpen(false)}
          moduleName={targetModuleForStart || 'General'}
          hasDraft={!!targetModuleForStart && hasDraft(targetModuleForStart)}
          onStartNew={() => {
              if (targetModuleForStart) startFreshInspection(targetModuleForStart);
              setIsStartModalOpen(false);
          }}
          onResume={() => {
              if (targetModuleForStart) resumeDraftInspection(targetModuleForStart);
              setIsStartModalOpen(false);
          }}
      />

      {upgradeFeature && <UpgradeModal featureName={upgradeFeature} onClose={() => setUpgradeFeature(null)} />}

      {isProfileModalOpen && currentUser && (
          <ProfileModal 
              user={currentUser}
              appScriptUrl={appScriptUrl}
              onClose={() => setIsProfileModalOpen(false)}
              showToast={showToast}
              onUpdateSuccess={(updatedUser) => {
                   setCurrentUser(updatedUser);
                   localStorage.setItem('safetyCheck_user', JSON.stringify(updatedUser));
              }}
          />
      )}

      {/* Report Preview Modal (Client Side View Only) */}
      {isReportModalOpen && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={handlePrint}
            title="Inspection Report"
          >
               <div className="print-only-container">
                    {activeModule === 'petroleum' ? (
                        <PrintablePetroleumReport data={selectedReportData || formInitialData} settings={settings} />
                    ) : activeModule === 'petroleum_v2' ? (
                        <PrintablePetroleumV2Report data={selectedReportData || formInitialData} settings={settings} />
                    ) : activeModule === 'acid' ? (
                        <PrintableAcidReport data={selectedReportData || formInitialData} settings={settings} />
                    ) : (
                        <PrintableGeneralReport data={selectedReportData || formInitialData} settings={settings} />
                    )}
               </div>
          </ReportViewerModal>
      )}

      {/* Hidden print element */}
      <div className="print-only hidden p-0 bg-white">
         {activeModule === 'petroleum' ? (
             <PrintablePetroleumReport data={selectedReportData || formInitialData} settings={settings} />
         ) : activeModule === 'petroleum_v2' ? (
             <PrintablePetroleumV2Report data={selectedReportData || formInitialData} settings={settings} />
         ) : activeModule === 'acid' ? (
             <PrintableAcidReport data={selectedReportData || formInitialData} settings={settings} />
         ) : (
             <PrintableGeneralReport data={selectedReportData || formInitialData} settings={settings} />
         )}
      </div>

      <div className="relative z-10 bg-gray-50 min-h-screen">
          <Sidebar 
            isOpen={isSidebarOpen} 
            onClose={() => setIsSidebarOpen(false)} 
            activeModule={activeModule}
            onSelectModule={(m) => {
                setActiveModule(m);
                setViewMode('dashboard');
            }}
            onLockedItemClick={(feature) => setUpgradeFeature(feature)}
            settings={settings}
            user={currentUser}
            onLogout={handleLogout}
            onEditProfile={() => setIsProfileModalOpen(true)}
            subscription={subscription} // Pass new subscription data
          />

          <div className="lg:pl-64 min-h-screen flex flex-col transition-all duration-300">
            {/* Global Subscription Alert */}
            <SubscriptionAlert 
                subscription={subscription} 
                user={currentUser} 
                onManage={() => { setActiveModule('settings'); setViewMode('dashboard'); }}
            />

            <header className="bg-emerald-950 border-b border-emerald-900 sticky top-0 z-40 shadow-sm">
              <div className="px-4 py-3 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                    <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-1 hover:bg-slate-800 rounded">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16"></path></svg>
                    </button>
                    <div className="flex flex-col">
                        <h1 className="text-lg md:text-xl font-bold flex items-center gap-2">
                            {activeModule === 'overview' ? 'Executive Dashboard' : 
                            activeModule === 'petroleum' ? 'Petroleum V1' : 
                            activeModule === 'petroleum_v2' ? 'Petroleum V2' : 
                            activeModule === 'acid' ? 'Acid' : 
                            activeModule === 'settings' ? 'System' :
                            activeModule === 'users' ? 'Users' :
                            activeModule === 'support' ? 'Support Hub' :
                            'SafetyCheck'}
                        </h1>
                        {isBackgroundFetching && (
                            <div className="flex items-center gap-1.5 text-[10px] text-emerald-300 animate-pulse">
                                Checking for updates...
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {offlineQueue.length > 0 && (
                        <button
                            onClick={syncOfflineQueue}
                            disabled={isSyncing} 
                            className={`hidden md:flex items-center gap-2 px-3 py-1 rounded-full text-xs font-bold transition-all
                                ${isSyncing ? 'bg-emerald-500 text-white cursor-wait' : 'bg-amber-500 text-white hover:bg-amber-600'}
                            `}
                        >
                            <span>{isSyncing ? 'Syncing...' : `Pending Sync (${offlineQueue.length})`}</span>
                        </button>
                    )}

                    <NotificationCenter 
                        notifications={notifications}
                        onMarkAsRead={(id) => handleMarkNotificationRead(id, (m) => { setActiveModule(m); setViewMode('dashboard'); })}
                        onDismiss={handleDismissNotification}
                        onClearAll={handleClearAllNotifications}
                        onAcknowledge={handleGlobalAcknowledge}
                        canAcknowledge={canAcknowledge}
                    />
                </div>
              </div>
            </header>

            {viewMode === 'form' ? (
                <InspectionFormView 
                    initialData={formInitialData}
                    activeModule={activeModule}
                    validationLists={validationLists}
                    settings={settings}
                    onSaveDraft={handleExitForm} 
                    onExit={() => handleExitForm()} 
                    onSubmit={handleGoogleSheetSubmit}
                    submissionStatus={submissionStatus}
                    onViewReport={handleViewReport}
                />
            ) : (
                <main className="flex-1 p-4 md:p-6 lg:p-8 max-w-6xl mx-auto w-full">
                  {activeModule === 'overview' && (
                      <OverviewDashboard 
                          appScriptUrl={appScriptUrl}
                          onNavigate={(module) => { setActiveModule(module); setViewMode('dashboard'); }}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'settings' && (
                      <SettingsView 
                          settings={settings}
                          setSettings={setSettings}
                          appScriptUrl={appScriptUrl}
                          setAppScriptUrl={setAppScriptUrl}
                          handleSaveSettings={handleSaveSettings}
                          isSavingSettings={isSavingSettings}
                          showToast={showToast}
                          user={currentUser} 
                      />
                  )}

                  {activeModule === 'users' && (
                      <UserManagementView 
                          currentUser={currentUser}
                          appScriptUrl={appScriptUrl}
                          showToast={showToast}
                          validationLists={validationLists}
                          settings={settings}
                      />
                  )}

                  {activeModule === 'support' && (
                      <SupportView 
                          appScriptUrl={appScriptUrl}
                          currentUser={currentUser}
                          showToast={showToast}
                          settings={settings}
                      />
                  )}

                  {activeModule === 'general' && (
                      <GeneralDashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('general')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'petroleum' && (
                      <PetroleumDashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('petroleum')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'petroleum_v2' && (
                      <PetroleumV2Dashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('petroleum_v2')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'acid' && (
                      <AcidDashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('acid')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}
                </main>
            )}
          </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, SystemSettings } from '../types';
import { BACKEND_SCRIPT_TEMPLATE } from '../constants';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(!appScriptUrl); // Only show if URL is missing
  const [showScriptModal, setShowScriptModal] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [isCopying, setIsCopying] = useState(false);
  const [logoError, setLogoError] = useState(false);

  // Password Change State
  const [showPasswordChange, setShowPasswordChange] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [tempUser, setTempUser] = useState<User | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!appScriptUrl) {
      setError("System Database URL is missing.");
      setShowConfig(true);
      return;
    }
    setError('');
    setIsLoading(true);

    try {
      // CRITICAL: First user registered (Bootstrapping) must be SuperAdmin
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          if (isRegistering) {
              setError("System Owner (SuperAdmin) created! Please log in.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              const rawUser = result.user;
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'other') safeRole = 'Other';

              const normalizedUser: User = {
                  ...rawUser,
                  role: safeRole,
                  position: rawUser.position || ''
              };

              // Check for Force Password Change
              if (normalizedUser.preferences?.mustChangePassword) {
                  setTempUser(normalizedUser);
                  setShowPasswordChange(true);
                  setIsLoading(false);
                  return; // Stop login flow until password changed
              }

              onLogin(normalizedUser);
          }
      } else if (result.code === 'NO_USERS') {
          setError("New Database detected. Create the System Owner account.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Authentication failed.");
      }

    } catch (err) {
      console.error("Login Error", err);
      setError("Connection failed. Check internet or Settings.");
    } finally {
      setIsLoading(false); // Only clear if not waiting for password change
    }
  };

  const handlePasswordChangeSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (newPassword.length < 4) {
          setError("Password too short (min 4 chars)");
          return;
      }
      if (newPassword !== confirmPassword) {
          setError("Passwords do not match");
          return;
      }

      setIsLoading(true);
      setError('');

      try {
          if (!tempUser) return;

          // Update password and clear the flag
          const updatedPrefs = { ...tempUser.preferences, mustChangePassword: false };

          const response = await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'update_user',
                  originalUsername: tempUser.username,
                  password: newPassword,
                  preferences: updatedPrefs
              })
          });

          const result = await response.json();
          if (result.status === 'success') {
              // Proceed with login using updated user object
              const finalUser = { ...tempUser, preferences: updatedPrefs };
              onLogin(finalUser);
          } else {
              setError("Failed to update password. Try again.");
              setIsLoading(false);
          }
      } catch (err) {
          setError("Connection failed during password update.");
          setIsLoading(false);
      }
  };

  const copyScript = () => {
      navigator.clipboard.writeText(BACKEND_SCRIPT_TEMPLATE);
      setIsCopying(true);
      setTimeout(() => setIsCopying(false), 2000);
  };

  if (showPasswordChange) {
      return (
        <div className="min-h-screen w-full bg-white flex items-center justify-center p-4 font-sans text-slate-600 relative overflow-hidden">
