                    >
                        {isLoading ? 'Updating...' : 'Update Password & Login'}
                    </button>
                </form>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen w-full bg-white flex items-center justify-center p-4 font-sans text-slate-600 relative overflow-hidden">
