                                )}
                                <button 
                                    onClick={() => handleCopyText(getAppUrl())}
                                    className="flex-1 py-2 bg-white/5 hover:bg-white/10 text-slate-300 text-xs font-bold rounded-lg border border-white/10 transition-colors flex items-center justify-center gap-1"
