function handleGetTickets(ss, body) {
    let ticketSheet = ss.getSheetByName('Support_Tickets');
    if (!ticketSheet || ticketSheet.getLastRow() <= 1) {
        return ContentService.createTextOutput(JSON.stringify({ status: "success", tickets: [] }))
           .setMimeType(ContentService.MimeType.JSON);
    }

    const data = ticketSheet.getDataRange().getValues();
    const tickets = [];

    // Robustly handle input, defaulting to safe strings
    const userRole = body.role ? String(body.role).toLowerCase() : "";
    const userEmail = body.email ? String(body.email).toLowerCase().trim() : ""; 
    const isAdmin = userRole === 'admin' || userRole === 'superadmin';

    for (let i = 1; i < data.length; i++) {
        const row = data[i];
        if(!row[0]) continue; // Skip empty rows

        const ticketOwnerEmail = row[6] ? String(row[6]).toLowerCase().trim() : "";
        const assignedAgent = row[11] ? String(row[11]) : ""; // Col 12 (Index 11) is Assigned_Agent

        // Looser matching logic:
        // 1. Admin sees all.
        // 2. Exact email match.
        // 3. User name matches partial email (e.g. user 'John' matches 'john@company.com' logic if used)

        if (isAdmin || (userEmail && ticketOwnerEmail === userEmail) || (ticketOwnerEmail && userEmail && ticketOwnerEmail.includes(userEmail))) {
            let comments = [];
            try {
                comments = row[10] ? JSON.parse(row[10]) : [];
            } catch(e) {
                comments = [];
            }

            tickets.push({
                ticketId: row[0],
                type: row[1],
                subject: row[2],
                description: row[3],
                priority: row[4],
                user: row[5],
                email: row[6],
                role: row[7],
                timestamp: row[8],
                status: row[9],
                comments: comments,
                assignedTo: assignedAgent
            });
        }
    }

    return ContentService.createTextOutput(JSON.stringify({ status: "success", tickets: tickets.reverse() }))
       .setMimeType(ContentService.MimeType.JSON);
}

function handleUpdateTicket(ss, body) {
    let ticketSheet = ss.getSheetByName('Support_Tickets');
    if (!ticketSheet) return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "DB Error" })).setMimeType(ContentService.MimeType.JSON);

    const data = ticketSheet.getDataRange().getValues();
    const ticketId = body.ticketId;
    let targetRowIndex = -1;
    let ticketOwnerEmail = "";
    let currentAssignedTo = "";

    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]) === ticketId) {
            targetRowIndex = i + 1;
            ticketOwnerEmail = String(data[i][6]);
            currentAssignedTo = data[i][11] ? String(data[i][11]) : "";
            break;
        }
    }

    if (targetRowIndex > -1) {
        let notifSheet = ss.getSheetByName('SystemNotification');
        if (!notifSheet) {
            notifSheet = ss.insertSheet('SystemNotification');
            notifSheet.appendRow(["Notification_ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "ActionLink"]);
        }

        // 1. Update Status
        if (body.status) {
            ticketSheet.getRange(targetRowIndex, 10).setValue(body.status);

            // Notify User of status change
            notifSheet.appendRow([
                "NOTIF-" + Date.now(),
                ticketOwnerEmail.toLowerCase().trim(),
                "info",
                "Ticket " + ticketId + " updated to status: " + body.status,
                new Date().toISOString(),
                "FALSE",
                "view:support"
            ]);
        }

        // 2. Reassign Ticket (SuperAdmin Action)
        if (body.assignedTo) {
            // Ensure Col 12 exists
            if (ticketSheet.getLastColumn() < 12) {
                 ticketSheet.getRange(1, 12).setValue("Assigned_Agent").setFontWeight("bold");
            }
            ticketSheet.getRange(targetRowIndex, 12).setValue(body.assignedTo);

            // Notify the new Agent (Assuming assignedTo is a name, we notify Admin role generally if we can't find specific email, or we rely on name matching in frontend notification filter if implemented strictly)
            // Ideally assignedTo is a username/email. If it's a name, the user needs to check notifications for 'Admin' or their role. 
            // For simplicity in this system, we notify 'Admin' role generally that a ticket was assigned, or the specific user if username provided.

            notifSheet.appendRow([
                "NOTIF-" + Date.now(),
                "Admin", 
                "info",
                "Ticket " + ticketId + " reassigned to " + body.assignedTo,
                new Date().toISOString(),
                "FALSE",
                "view:support"
            ]);
        }

        // 3. Add Comment
        if (body.comment) {
            const currentCommentsJson = ticketSheet.getRange(targetRowIndex, 11).getValue();
            let comments = [];
            try {
                comments = currentCommentsJson ? JSON.parse(currentCommentsJson) : [];
            } catch(e) {
                comments = [];
            }

            comments.push(body.comment);
            ticketSheet.getRange(targetRowIndex, 11).setValue(JSON.stringify(comments));

            const isResponderAdmin = String(body.comment.role).toLowerCase() === 'admin' || String(body.comment.role).toLowerCase() === 'superadmin';

            // If Admin replies -> Notify User
            // If User replies -> Notify Assigned Agent (or Admin if none)

            let recipient = '';
            let msg = '';

            if (isResponderAdmin) {
                recipient = ticketOwnerEmail.toLowerCase().trim();
                msg = "Ticket " + ticketId + ": New response from Support";
            } else {
                // User replying
                // If there is an assigned agent (by name/username), ideally we notify them. 
                // But since we use 'Admin' as a catch-all for the support team view:
                recipient = 'Admin'; 
                msg = "Ticket " + ticketId + ": New response from User";
            }

            notifSheet.appendRow([
                "NOTIF-" + Date.now(),
                recipient,
                "info",
                msg,
                new Date().toISOString(),
                "FALSE",
                "view:support"
            ]);
        }

        return ContentService.createTextOutput(JSON.stringify({ status: "success" })).setMimeType(ContentService.MimeType.JSON);
    }

    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "Ticket not found" })).setMimeType(ContentService.MimeType.JSON);
}

function updateValidationData(ss, body) {
  try {
     const row = body.row;
     const sheetName = body.sheet;

     let truck, trailer, driver, inspector, location;

     if (sheetName === 'General') {
         truck = row[2]; trailer = row[3]; inspector = row[4]; driver = row[5]; location = row[6];
     } else {
         truck = row[2]; trailer = row[3]; location = row[5]; inspector = row[7]; driver = row[8];
     }

     updateValidationSingle(ss, 'Truck_Reg_No', truck);
     updateValidationSingle(ss, 'Trailer_Reg_No', trailer);
     updateValidationSingle(ss, 'Driver_Name', driver);
     updateValidationSingle(ss, 'Inspector_Name', inspector);
     updateValidationSingle(ss, 'Location', location);

  } catch (e) {
  }
}

function updateValidationSingle(ss, headerName, value) {
     if (!value || String(value).trim() === "") return;
     const valStr = String(value).trim();

     let vSheet = ss.getSheetByName('Validation_Data');
     if (!vSheet) {
        vSheet = ss.insertSheet('Validation_Data');
        vSheet.appendRow(['Truck_Reg_No', 'Trailer_Reg_No', 'Driver_Name', 'Inspector_Name', 'Location', 'Position']);
        vSheet.setFrozenRows(1);
        vSheet.getRange(1,1,1,6).setFontWeight('bold');
     }

     const headers = vSheet.getRange(1, 1, 1, vSheet.getLastColumn()).getValues()[0];
     let colIndex = headers.indexOf(headerName) + 1;

     if (colIndex < 1) {
         colIndex = headers.length + 1;
         vSheet.getRange(1, colIndex).setValue(headerName);
         vSheet.getRange(1, colIndex).setFontWeight('bold');
     }

     const fullCol = vSheet.getRange(1, colIndex, vSheet.getMaxRows(), 1).getValues().flat().map(String);
     if (!fullCol.includes(valStr)) {
         let targetRow = 1;
         for(let i=1; i<fullCol.length; i++) {
             if(fullCol[i] === "") {
                 targetRow = i + 1;
                 break;
             }
         }
         if (targetRow === 1) targetRow = vSheet.getLastRow() + 1;
         vSheet.getRange(targetRow, colIndex).setValue(valStr);
     }
}
`;

const BACKEND_PDF = `
function createPdf(data) {
  var html = "<!DOCTYPE html><html><head><style>" +
    "body{font-family:Helvetica,sans-serif;padding:20px;color:#333}" +
    "h1{color:#2563eb;border-bottom:2px solid #e5e7eb;padding-bottom:10px;margin-bottom:20px}" +
    ".grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:20px;background:#f9fafb;padding:15px;border-radius:8px}" +
    ".item{display:flex;justify-content:space-between;border-bottom:1px solid #f3f4f6;padding:8px 0}" +
    ".status{font-weight:bold;text-transform:uppercase;font-size:0.8em}" +
    ".bad{color:#dc2626}.good{color:#16a34a}.attn{color:#d97706}.nil{color:#9ca3af}" +
    "</style></head><body>";

  html += "<h1>" + (data.title || "Inspection Report") + "</h1>";

  html += "<div class='grid'>";
  html += "<div><strong>Vehicle:</strong> " + (data.truckNo || "-") + "</div>";
  html += "<div><strong>Trailer:</strong> " + (data.trailerNo || "-") + "</div>";
  html += "<div><strong>Job Card:</strong> " + (data.jobCard || "-") + "</div>";
  html += "<div><strong>Driver:</strong> " + (data.driverName || "-") + "</div>";
  html += "<div><strong>Inspector:</strong> " + (data.inspectedBy || "-") + "</div>";
  html += "<div><strong>Date:</strong> " + (data.timestamp ? new Date(data.timestamp).toLocaleString() : "-") + "</div>";
  html += "<div><strong>Location:</strong> " + (data.location || "-") + "</div>";
  html += "<div><strong>Odometer:</strong> " + (data.odometer || "-") + "</div>";
  html += "</div>";

  html += "<h3>Checklist</h3>";
  if (data.items && data.items.length) {
    data.items.forEach(function(item) {
      var s = item.status || "Nil";
      var cls = "nil";
      if (s === 'Good') cls = "good";
      if (s === 'Bad') cls = "bad";
      if (s === 'Needs Attention') cls = "attn";

      html += "<div class='item'>";
      html += "<span>" + item.label + "</span>";
      html += "<span class='status " + cls + "'>" + s + "</span>";
      html += "</div>";
    });
  }

  html += "<h3>Summary</h3>";
  html += "<p><strong>Rating:</strong> " + (data.rate || "-") + "/5</p>";
  html += "<p><strong>Remarks:</strong> " + (data.remarks || "None") + "</p>";

  html += "<p style='font-size:10px;color:#999;margin-top:30px;border-top:1px solid #eee;padding-top:10px'>Generated by SafetyCheck Pro</p>";
  html += "</body></html>";

  var blob = Utilities.newBlob(html, "text/html", "report.html");
  var pdf = blob.getAs("application/pdf");
  pdf.setName("Report_" + (data.truckNo || "Vehicle") + "_" + new Date().toISOString().slice(0,10) + ".pdf");
  return pdf;
}
`;

const BACKEND_EMAIL = `
function sendEmailNotifications(ss, body, sheetName) {
  try {
    var settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return;

    var lastRow = settingsSheet.getLastRow();
    if (lastRow < 2) return; // No settings

    // Assumes Col B (index 1) is ManagerEmail
    var email = settingsSheet.getRange(lastRow, 2).getValue(); 
    if (!email || email === "") return;

    var reportData = body.reportData;
    if (!reportData) return;

    var subject = "Inspection Report: " + (reportData.truckNo || "Unknown");
    if (reportData.rate <= 2) subject = "URGENT [FAIL]: " + subject;
    else if (reportData.rate == 3) subject = "ATTENTION: " + subject;
    else subject = "SUCCESS: " + subject;

    var message = "A new inspection has been submitted.\\n\\n";
    message += "Vehicle: " + reportData.truckNo + "\\n";
    message += "Inspector: " + reportData.inspectedBy + "\\n";
    message += "Result: " + reportData.rate + "/5\\n";
    message += "Remarks: " + reportData.remarks + "\\n\\n";
    message += "Attached is the PDF report.";

    var pdf = createPdf(reportData);

    MailApp.sendEmail({
      to: email,
      subject: subject,
      body: message,
      attachments: [pdf]
    });

  } catch (e) {
    handleLog(ss, "EMAIL_ERROR", e.toString());
    console.error(e);
  }
}
`;

export const BACKEND_SCRIPT_TEMPLATE = BACKEND_CORE + BACKEND_AUTH + BACKEND_DATA + BACKEND_PDF + BACKEND_EMAIL;

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import Sidebar from './components/layout/Sidebar';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';

// Reports (Only for Preview now)
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  // --- CORE HOOKS ---
  const { currentUser, setCurrentUser, handleLogin, handleLogout } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();

  // Subscription Hook - The heart of the new security model
  const { subscription, isLocked, refreshSubscription } = useSubscription(appScriptUrl, currentUser);

  // Global hack to pass lock state to deep components without prop drilling hell immediately
  // Ideally this should be context, but for quick refactor:
  if (typeof window !== 'undefined') {
      (window as any).isSubscriptionLocked = isLocked;
  }

  // Navigation State
  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');

  // UI State
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [upgradeFeature, setUpgradeFeature] = useState<string | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

  // --- DATA HOOKS ---
  const { historyList, isLoadingHistory, isBackgroundFetching, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule);

  const showToast = (message: string, type: 'success' | 'error' | 'info') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  const { submissionStatus, setSubmissionStatus, offlineQueue, isSyncing, syncOfflineQueue, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  const { notifications, fetchNotifications, handleMarkNotificationRead, handleDismissNotification, handleGlobalAcknowledge, handleClearAllNotifications } = useNotifications(appScriptUrl, currentUser, showToast);

  // --- LOCAL STATE ---
  const [isStartModalOpen, setIsStartModalOpen] = useState(false);
  const [targetModuleForStart, setTargetModuleForStart] = useState<string | null>(null);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);

  // Form Init State
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  // Access Control Effect
  useEffect(() => {
      if (currentUser) {
          // Normalize role check
          const role = currentUser.role || '';
          const isAdmin = role === 'Admin' || role === 'SuperAdmin';

          if (!isAdmin && (activeModule === 'settings' || activeModule === 'users')) {
              showToast("Access Restricted to Admins.", 'error');
              setActiveModule('overview');
          }
      }
  }, [activeModule, currentUser]);

  // Data Fetching Effect
  useEffect(() => {
    if (!currentUser || !appScriptUrl) return;

    if (navigator.onLine) {
        fetchNotifications();
        if (offlineQueue.length > 0) syncOfflineQueue();
    }

    // Fetch history when entering a module dashboard
    if (viewMode === 'dashboard' && ['general', 'petroleum', 'petroleum_v2', 'acid'].includes(activeModule)) {
       fetchHistory(false);
    }
  }, [activeModule, viewMode, currentUser]);


  // --- DRAFT LOGIC ---
  const getDraftKey = (module: string) => `sc_draft_${module}`;
  const hasDraft = (module: string) => !!localStorage.getItem(getDraftKey(module));

  const loadDraft = (module: string) => {
      const draft = localStorage.getItem(getDraftKey(module));
      if (draft) {
          try { return JSON.parse(draft); } catch(e) { return null; }
      }
      return null;
  };

  const clearDraft = (module: string) => localStorage.removeItem(getDraftKey(module));

  const handleInitiateStartInspection = (module: string) => {
      // Prevent start if locked
      if (isLocked) {
          showToast("Subscription Expired. Cannot start inspection.", 'error');
          return;
      }

      if (hasDraft(module)) {
          setTargetModuleForStart(module);
          setIsStartModalOpen(true);
      } else {
          startFreshInspection(module);
      }
  };

  const startFreshInspection = (module: string) => {
      clearDraft(module); 
      setFormInitialData({ 
          ...INITIAL_DATA, 
          timestamp: new Date().toISOString(),
          inspectedBy: currentUser?.name || '' 
      });
      setViewMode('form');
  };

  const resumeDraftInspection = (module: string) => {
      const draft = loadDraft(module);
      if (draft) {
          setFormInitialData(draft);
          setViewMode('form');
          showToast("Draft resumed.", 'info');
      } else {
          showToast("Failed to load draft. Starting new.", 'error');
          startFreshInspection(module);
      }
  };

  const handleExitForm = (savedData?: InspectionData) => {
      if (savedData) {
          localStorage.setItem(getDraftKey(activeModule), JSON.stringify(savedData));
          showToast("Draft saved successfully.", 'success');
      }
      setViewMode('dashboard');
  };

  // --- SUBMISSION LOGIC ---
  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (currentUser?.role && !['Admin', 'Inspector', 'SuperAdmin'].includes(currentUser.role)) {
        showToast("Access Denied: View Only Account.", 'error');
        return;
    }

    if (!appScriptUrl) {
        showToast("System Not Connected. Please configure Settings.", 'error');
        setActiveModule('settings');
        return;
    }

    setSubmissionStatus('submitting');

    const recordId = crypto.randomUUID();
    let targetSheet = "General";
    let targetHeaders = SHEET_HEADERS;

    // Prepare Data Payload for Server-Side PDF Generation
    let reportItems: { category: string, label: string, status: string }[] = [];
    let reportTitle = "General Inspection Report";

    if (activeModule === 'petroleum') {
        targetSheet = "Petroleum";
        targetHeaders = PETROLEUM_HEADERS;
        reportTitle = "Petroleum Tanker Inspection";
        reportItems = PETROLEUM_INSPECTION_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    } else if (activeModule === 'petroleum_v2') {
        targetSheet = "Petroleum_V2";
        targetHeaders = PETROLEUM_V2_HEADERS;
        reportTitle = "Petroleum Tanker Inspection V2";
        reportItems = PETROLEUM_V2_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    } else if (activeModule === 'acid') {
        targetSheet = "Acid";
        targetHeaders = ACID_HEADERS;
        reportTitle = "Acid Tanker Inspection";
        reportItems = ACID_INSPECTION_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    } else {
        // General
        reportItems = INSPECTION_ITEMS.map(item => ({
            category: item.category,
            label: item.label,
            status: String((formData as any)[item.id] || 'N/A')
        }));
    }

    const reportData = {
        title: reportTitle,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard || 'N/A',
        driverName: formData.driverName,
        inspectedBy: formData.inspectedBy,
        location: formData.location,
        odometer: formData.odometer,
        timestamp: formData.timestamp,
        remarks: formData.remarks,
        rate: formData.rate,
        items: reportItems,
        signatures: {
            inspector: formData.inspectorSignature,
            driver: formData.driverSignature
        },
        photos: {
            front: formData.photoFront,
            ls: formData.photoLS,
            rs: formData.photoRS,
            back: formData.photoBack,
            damage: formData.photoDamage
        },
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const rowData = targetHeaders.map(header => {
        if (header === 'id') return recordId;
        const val = (formData as any)[header];
        return (val === null || val === undefined) ? "" : val;
    });

    const payload = {
        sheet: targetSheet,
        action: "create",
        row: rowData,
        headers: targetHeaders,
        id: recordId,
        reportData: reportData
    };

    if (!navigator.onLine) {
        addToQueue(payload);
        clearDraft(activeModule);
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
             startFreshInspection(activeModule); 
             setViewMode('dashboard');
             setSubmissionStatus('idle');
             showToast("Offline Mode: Report Saved. Will sync when online.", 'info');
        }, 2000);
        return;
    }

    try {
        await fetch(appScriptUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            mode: 'no-cors', 
            headers: { 'Content-Type': 'text/plain' }
        });

        clearDraft(activeModule);
        setSubmissionStatus('success');

        setTimeout(() => {
             startFreshInspection(activeModule); 
             setViewMode('dashboard');
             setSubmissionStatus('idle');
             fetchHistory(true); 
             fetchNotifications();
             showToast("Inspection Submitted & Email Sent!", 'success');
        }, 2500);

    } catch (error) {
        console.error("Submission Error", error);
        addToQueue(payload);
        clearDraft(activeModule); 
        setSubmissionStatus('offline_saved');
        setTimeout(() => {
             startFreshInspection(activeModule); 
             setViewMode('dashboard');
             setSubmissionStatus('idle');
             showToast("Network Error: Report queued for sync.", 'info');
        }, 2500);
    }
  };

  const handlePrint = () => window.print();
  const handleQuickPrint = (item: InspectionData) => {
      setSelectedReportData(item);
      setTimeout(() => window.print(), 500);
  };
  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  // --- RENDER ---
  if (!currentUser) {
      return (
          <LoginView 
            onLogin={handleLogin} 
            appScriptUrl={appScriptUrl}
            setAppScriptUrl={setAppScriptUrl}
            settings={settings}
          />
      );
  }

  const canAcknowledge = ['Admin', 'Maintenance', 'Inspector', 'SuperAdmin'].includes(currentUser.role || '');

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <InspectionStartModal 
          isOpen={isStartModalOpen}
          onClose={() => setIsStartModalOpen(false)}
          moduleName={targetModuleForStart || 'General'}
          hasDraft={!!targetModuleForStart && hasDraft(targetModuleForStart)}
          onStartNew={() => {
              if (targetModuleForStart) startFreshInspection(targetModuleForStart);
              setIsStartModalOpen(false);
          }}
          onResume={() => {
              if (targetModuleForStart) resumeDraftInspection(targetModuleForStart);
              setIsStartModalOpen(false);
          }}
      />

      {upgradeFeature && <UpgradeModal featureName={upgradeFeature} onClose={() => setUpgradeFeature(null)} />}

      {isProfileModalOpen && currentUser && (
          <ProfileModal 
              user={currentUser}
              appScriptUrl={appScriptUrl}
              onClose={() => setIsProfileModalOpen(false)}
              showToast={showToast}
              onUpdateSuccess={(updatedUser) => {
                   setCurrentUser(updatedUser);
                   localStorage.setItem('safetyCheck_user', JSON.stringify(updatedUser));
              }}
          />
      )}

      {/* Report Preview Modal (Client Side View Only) */}
      {isReportModalOpen && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={handlePrint}
            title="Inspection Report"
          >
               <div className="print-only-container">
                    {activeModule === 'petroleum' ? (
                        <PrintablePetroleumReport data={selectedReportData || formInitialData} settings={settings} />
                    ) : activeModule === 'petroleum_v2' ? (
                        <PrintablePetroleumV2Report data={selectedReportData || formInitialData} settings={settings} />
                    ) : activeModule === 'acid' ? (
                        <PrintableAcidReport data={selectedReportData || formInitialData} settings={settings} />
                    ) : (
                        <PrintableGeneralReport data={selectedReportData || formInitialData} settings={settings} />
                    )}
               </div>
          </ReportViewerModal>
      )}

      {/* Hidden print element */}
      <div className="print-only hidden p-0 bg-white">
         {activeModule === 'petroleum' ? (
             <PrintablePetroleumReport data={selectedReportData || formInitialData} settings={settings} />
         ) : activeModule === 'petroleum_v2' ? (
             <PrintablePetroleumV2Report data={selectedReportData || formInitialData} settings={settings} />
         ) : activeModule === 'acid' ? (
             <PrintableAcidReport data={selectedReportData || formInitialData} settings={settings} />
         ) : (
             <PrintableGeneralReport data={selectedReportData || formInitialData} settings={settings} />
         )}
      </div>

      <div className="relative z-10 bg-gray-50 min-h-screen">
          <Sidebar 
            isOpen={isSidebarOpen} 
            onClose={() => setIsSidebarOpen(false)} 
            activeModule={activeModule}
            onSelectModule={(m) => {
                setActiveModule(m);
                setViewMode('dashboard');
            }}
            onLockedItemClick={(feature) => setUpgradeFeature(feature)}
            settings={settings}
            user={currentUser}
            onLogout={handleLogout}
            onEditProfile={() => setIsProfileModalOpen(true)}
            subscription={subscription} // Pass new subscription data
          />

          <div className="lg:pl-64 min-h-screen flex flex-col transition-all duration-300">
            {/* Global Subscription Alert */}
            <SubscriptionAlert 
                subscription={subscription} 
                user={currentUser} 
                onManage={() => { setActiveModule('settings'); setViewMode('dashboard'); }}
            />

            <header className="bg-emerald-950 border-b border-emerald-900 sticky top-0 z-40 shadow-sm">
              <div className="px-4 py-3 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                    <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-1 hover:bg-slate-800 rounded">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16"></path></svg>
                    </button>
                    <div className="flex flex-col">
                        <h1 className="text-lg md:text-xl font-bold flex items-center gap-2">
                            {activeModule === 'overview' ? 'Executive Dashboard' : 
                            activeModule === 'petroleum' ? 'Petroleum V1' : 
                            activeModule === 'petroleum_v2' ? 'Petroleum V2' : 
                            activeModule === 'acid' ? 'Acid' : 
                            activeModule === 'settings' ? 'System' :
                            activeModule === 'users' ? 'Users' :
                            activeModule === 'support' ? 'Support Hub' :
                            'SafetyCheck'}
                        </h1>
                        {isBackgroundFetching && (
                            <div className="flex items-center gap-1.5 text-[10px] text-emerald-300 animate-pulse">
                                Checking for updates...
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {offlineQueue.length > 0 && (
                        <button
                            onClick={syncOfflineQueue}
                            disabled={isSyncing} 
                            className={`hidden md:flex items-center gap-2 px-3 py-1 rounded-full text-xs font-bold transition-all
                                ${isSyncing ? 'bg-emerald-500 text-white cursor-wait' : 'bg-amber-500 text-white hover:bg-amber-600'}
                            `}
                        >
                            <span>{isSyncing ? 'Syncing...' : `Pending Sync (${offlineQueue.length})`}</span>
                        </button>
                    )}

                    <NotificationCenter 
                        notifications={notifications}
                        onMarkAsRead={(id) => handleMarkNotificationRead(id, (m) => { setActiveModule(m); setViewMode('dashboard'); })}
                        onDismiss={handleDismissNotification}
                        onClearAll={handleClearAllNotifications}
                        onAcknowledge={handleGlobalAcknowledge}
                        canAcknowledge={canAcknowledge}
                    />
                </div>
              </div>
            </header>

            {viewMode === 'form' ? (
                <InspectionFormView 
                    initialData={formInitialData}
                    activeModule={activeModule}
                    validationLists={validationLists}
                    settings={settings}
                    onSaveDraft={handleExitForm} 
                    onExit={() => handleExitForm()} 
                    onSubmit={handleGoogleSheetSubmit}
                    submissionStatus={submissionStatus}
                    onViewReport={handleViewReport}
                />
            ) : (
                <main className="flex-1 p-4 md:p-6 lg:p-8 max-w-6xl mx-auto w-full">
                  {activeModule === 'overview' && (
                      <OverviewDashboard 
                          appScriptUrl={appScriptUrl}
                          onNavigate={(module) => { setActiveModule(module); setViewMode('dashboard'); }}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'settings' && (
                      <SettingsView 
                          settings={settings}
                          setSettings={setSettings}
                          appScriptUrl={appScriptUrl}
                          setAppScriptUrl={setAppScriptUrl}
                          handleSaveSettings={handleSaveSettings}
                          isSavingSettings={isSavingSettings}
                          showToast={showToast}
                          user={currentUser} 
                      />
                  )}

                  {activeModule === 'users' && (
                      <UserManagementView 
                          currentUser={currentUser}
                          appScriptUrl={appScriptUrl}
                          showToast={showToast}
                          validationLists={validationLists}
                          settings={settings}
                      />
                  )}

                  {activeModule === 'support' && (
                      <SupportView 
                          appScriptUrl={appScriptUrl}
                          currentUser={currentUser}
                          showToast={showToast}
                          settings={settings}
                          validationLists={validationLists}
                      />
                  )}

                  {activeModule === 'general' && (
                      <GeneralDashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('general')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'petroleum' && (
                      <PetroleumDashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('petroleum')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'petroleum_v2' && (
                      <PetroleumV2Dashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('petroleum_v2')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}

                  {activeModule === 'acid' && (
                      <AcidDashboard 
                          stats={stats}
                          startNewInspection={() => handleInitiateStartInspection('acid')}
                          fetchHistory={() => fetchHistory(true)}
                          isLoadingHistory={isLoadingHistory}
                          historyList={historyList}
                          onViewReport={handleViewReport}
                          onPrint={handleQuickPrint}
                          userRole={currentUser?.role}
                      />
                  )}
                </main>
            )}
          </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, SystemSettings, SupportTicket, TicketComment, ValidationLists } from '../types';

interface SupportViewProps {
    appScriptUrl: string;
    currentUser: User | null;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    settings?: SystemSettings;
    validationLists?: ValidationLists;
}

const SupportView: React.FC<SupportViewProps> = ({ appScriptUrl, currentUser, showToast, settings, validationLists }) => {
    // Navigation State
    const [activeTab, setActiveTab] = useState<'create' | 'list'>('create');
    const [selectedTicket, setSelectedTicket] = useState<SupportTicket | null>(null);

    // Form State
    const [ticketType, setTicketType] = useState<'Issue' | 'Feature' | 'Other'>('Issue');
    const [subject, setSubject] = useState('');
    const [description, setDescription] = useState('');
    const [priority, setPriority] = useState('Medium');
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Data State
    const [tickets, setTickets] = useState<SupportTicket[]>([]);
    const [isLoadingTickets, setIsLoadingTickets] = useState(false);

    // Reply State
    const [replyText, setReplyText] = useState('');
    const [isSendingReply, setIsSendingReply] = useState(false);

    // Assignment State
    const [assignAgent, setAssignAgent] = useState('');
    const [isAssigning, setIsAssigning] = useState(false);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const isSuperAdmin = currentUser?.role === 'SuperAdmin';

    // Calculate Active Tickets for Badge
    const activeTicketCount = tickets.filter(t => t.status !== 'Closed').length;

    useEffect(() => {
        if (activeTab === 'list') {
            fetchTickets();
        }
    }, [activeTab]);

    const fetchTickets = async (retryCount = 0) => {
        if (!appScriptUrl || !currentUser) return;

        // Only show loading spinner on first attempt
        if (retryCount === 0) setIsLoadingTickets(true);

        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ 
                    action: 'get_tickets',
                    // CRITICAL: Normalize to lowercase to match backend storage
                    email: currentUser.username.toLowerCase().trim(), 
                    role: currentUser.role
                })
            });
            const result = await response.json();

            if (result.status === 'success') {
                // If we get tickets, update state
                if (result.tickets.length > 0) {
                    setTickets(result.tickets);
                } else if (retryCount < 2) {
                    // PROFESSIONAL: If we expect data but get none (latency), retry silently
                    setTimeout(() => fetchTickets(retryCount + 1), 1500);
                    return; 
                } else {
                    // Only set empty if retries failed, but preserve existing if we have them locally (Optimistic)
                    if (tickets.length === 0) setTickets([]);
                }
            }
        } catch (e) {
            console.error("Ticket fetch failed", e);
        } finally {
            if (retryCount === 0) setIsLoadingTickets(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!appScriptUrl) {
            showToast("System offline. Please check settings.", "error");
            return;
        }

        setIsSubmitting(true);
        try {
            const payload = {
                action: 'submit_support_ticket',
                type: ticketType,
                subject,
                description,
                priority,
                user: currentUser?.name || 'Anonymous',
                // CRITICAL: Normalize to lowercase for consistent retrieval
                email: (currentUser?.username || 'N/A').toLowerCase().trim(), 
                role: currentUser?.role || 'N/A'
            };

            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload)
            });

            const result = await response.json();

            if (result.status === 'success') {
                showToast(`Ticket #${result.ticketId} created successfully.`, "success");

                // --- OPTIMISTIC UI UPDATE (Professional UX) ---
                // Add ticket to local state immediately so user sees it instantly without waiting for fetch
                const newTicket: SupportTicket = {
                    ticketId: result.ticketId,
                    type: ticketType,
                    subject: subject,
                    description: description,
                    priority: priority,
                    user: currentUser?.name || 'Me',
                    email: currentUser?.username || '',
                    role: currentUser?.role || 'User',
                    timestamp: new Date().toISOString(),
                    status: 'Open',
                    comments: []
                };

                setTickets(prev => [newTicket, ...prev]);

                // Clear Form
                setSubject('');
                setDescription('');
                setPriority('Medium');

                // Switch View
                setActiveTab('list');

                // Trigger background fetch to sync with server eventually
                setTimeout(() => fetchTickets(), 1000);
            } else {
                throw new Error(result.message || "Unknown error");
            }
        } catch (error) {
            console.error("Submit Error", error);
            showToast("Failed to submit ticket. Please check connection.", "error");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleReply = async () => {
        if (!replyText.trim() || !selectedTicket) return;
        setIsSendingReply(true);

        const newComment: TicketComment = {
            user: currentUser?.name || 'User',
            role: currentUser?.role || 'User',
            message: replyText,
            timestamp: new Date().toISOString()
        };

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_ticket',
                    ticketId: selectedTicket.ticketId,
                    comment: newComment
                }),
                mode: 'no-cors'
            });

            // Optimistic update
            const updatedTicket = {
                ...selectedTicket,
                comments: [...(selectedTicket.comments || []), newComment]
            };
            setSelectedTicket(updatedTicket);
            setTickets(prev => prev.map(t => t.ticketId === updatedTicket.ticketId ? updatedTicket : t));

            setReplyText('');
            // Optional: Scroll to bottom of chat if implemented
        } catch (e) {
            showToast("Failed to send reply", "error");
        } finally {
            setIsSendingReply(false);
        }
    };

    const handleStatusChange = async (newStatus: any) => {
        if (!selectedTicket) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_ticket',
                    ticketId: selectedTicket.ticketId,
                    status: newStatus
                }),
                mode: 'no-cors'
            });

            const updatedTicket = { ...selectedTicket, status: newStatus };
            setSelectedTicket(updatedTicket);
            setTickets(prev => prev.map(t => t.ticketId === updatedTicket.ticketId ? updatedTicket : t));
            showToast(`Status updated to ${newStatus}`, "success");
        } catch(e) {
            showToast("Failed to update status", "error");
        }
    };

    const handleReassign = async () => {
        if (!selectedTicket || !assignAgent || !isSuperAdmin) return;
        setIsAssigning(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_ticket',
                    ticketId: selectedTicket.ticketId,
                    assignedTo: assignAgent
                }),
                mode: 'no-cors'
            });

            const updatedTicket = { ...selectedTicket, assignedTo: assignAgent };
            setSelectedTicket(updatedTicket);
            setTickets(prev => prev.map(t => t.ticketId === updatedTicket.ticketId ? updatedTicket : t));
            showToast(`Ticket reassigned to ${assignAgent}`, "success");
            setAssignAgent('');
        } catch(e) {
            showToast("Failed to reassign ticket", "error");
        } finally {
            setIsAssigning(false);
        }
    };

    // Get the current URL of the app to share
    const getAppUrl = () => {
        return settings?.webAppUrl || window.location.origin + window.location.pathname;
    };

    const getShareMessage = () => {
        const webUrl = getAppUrl();
        const mobileUrl = settings?.mobileApkLink || 'Contact Admin for APK';
        const company = settings?.companyName || 'SafetyCheck Pro';

        return {
            title: `Access ${company} Inspection System`,
            text: `Here are the access details for the ${company} Digital Inspection System.\n\nWeb Portal: ${webUrl}\nMobile App: ${mobileUrl}\n\nDemo Credentials:\nUser: admin\nPass: 123456`
        };
    };

    const handleProfessionalShare = async () => {
        const { title, text } = getShareMessage();
        const url = getAppUrl();

        if (navigator.share) {
            try {
                await navigator.share({
                    title: title,
                    text: text,
                    url: url
                });
                showToast("Shared successfully!", "success");
            } catch (err) {
                // User cancelled or error
            }
        } else {
            handleCopyText(`${title}\n\n${text}`);
        }
    };

    const handleCopyText = (text: string) => {
        navigator.clipboard.writeText(text).then(() => {
            showToast("Details copied to clipboard!", "success");
        }).catch(() => {
            showToast("Failed to copy. Please manually copy the details.", "error");
        });
    };

    // --- SUB-COMPONENTS ---

    const TicketList = () => (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden min-h-[400px] flex flex-col">
            <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-slate-50">
                <h3 className="font-bold text-gray-700 text-sm">Your Tickets</h3>
                <button 
                    onClick={() => fetchTickets(0)}
                    className="text-xs flex items-center gap-1 text-blue-600 hover:text-blue-800 font-medium"
                >
                    <svg className={`w-3 h-3 ${isLoadingTickets ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                    Refresh List
                </button>
            </div>

            {isLoadingTickets && tickets.length === 0 ? (
                <div className="flex-1 flex flex-col items-center justify-center p-12 text-gray-400">
                    <div className="w-8 h-8 border-4 border-blue-100 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p className="text-sm">Retrieving tickets...</p>
                </div>
            ) : tickets.length === 0 ? (
                <div className="flex-1 flex flex-col items-center justify-center p-12 text-center">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
                        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
                    </div>
                    <p className="text-gray-500 font-medium">No tickets found.</p>
                    <p className="text-xs text-gray-400 mt-2 max-w-xs">If you submitted a request, it should appear here. Click refresh to check again.</p>
                </div>
            ) : (
                <div className="divide-y divide-gray-100 overflow-y-auto max-h-[500px]">
                    {tickets.map(ticket => (
                        <div 
                            key={ticket.ticketId} 
                            onClick={() => setSelectedTicket(ticket)}
                            className="p-4 hover:bg-slate-50 cursor-pointer transition flex items-center justify-between group"
                        >
                            <div className="min-w-0">
                                <div className="flex items-center gap-2 mb-1">
                                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border 
                                        ${ticket.status === 'Open' ? 'bg-blue-50 text-blue-600 border-blue-100' :
                                          ticket.status === 'Resolved' ? 'bg-green-50 text-green-600 border-green-100' :
                                          'bg-amber-50 text-amber-600 border-amber-100'}`}>
                                        {ticket.status}
                                    </span>
                                    <span className="text-xs font-mono text-gray-400">#{ticket.ticketId}</span>
                                    <span className="text-xs text-gray-400">• {new Date(ticket.timestamp).toLocaleDateString()}</span>
                                    {ticket.assignedTo && isAdmin && (
                                        <span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded text-slate-600 border border-slate-200">
                                            Assigned: {ticket.assignedTo}
                                        </span>
                                    )}
                                </div>
                                <h4 className="font-bold text-gray-800 text-sm truncate">{ticket.subject}</h4>
                                <p className="text-xs text-gray-500 truncate mt-0.5">{ticket.description}</p>
                            </div>
                            <div className="text-gray-300 group-hover:text-blue-500 transition-colors">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );

    const TicketDetail = () => {
        if (!selectedTicket) return null;
        const statusColors: any = { 'Open': 'bg-blue-500', 'In Progress': 'bg-amber-500', 'Resolved': 'bg-green-500', 'Closed': 'bg-gray-500' };

        // Auto-scroll to bottom of chat
        const messagesEndRef = useRef<HTMLDivElement>(null);
        const scrollToBottom = () => {
            messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
        };
        useEffect(() => {
            scrollToBottom();
        }, [selectedTicket.comments]);

        return (
            <div className="bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden flex flex-col h-[calc(100vh-200px)] min-h-[500px]">
                {/* Header - Rigid */}
                <div className="bg-slate-50 px-6 py-4 border-b border-gray-200 flex flex-col md:flex-row justify-between items-start md:items-center gap-3 shrink-0">
                    <div>
                        <button onClick={() => setSelectedTicket(null)} className="text-xs font-bold text-gray-500 hover:text-gray-800 flex items-center gap-1 mb-2">
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"></path></svg> Back
                        </button>
                        <h3 className="font-bold text-lg text-gray-800 line-clamp-1">{selectedTicket.subject}</h3>
                        <div className="flex items-center gap-2 mt-1 flex-wrap">
                            <span className="text-xs font-mono text-gray-400">#{selectedTicket.ticketId}</span>
                            <span className={`w-2 h-2 rounded-full ${statusColors[selectedTicket.status] || 'bg-gray-400'}`}></span>
                            <span className="text-xs text-gray-500">{selectedTicket.status}</span>
                            {selectedTicket.assignedTo && (
                                <span className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded border border-indigo-100 ml-2">
                                    Agent: {selectedTicket.assignedTo}
                                </span>
                            )}
                        </div>
                    </div>

                    {isAdmin && (
                        <div className="flex flex-col gap-2 w-full md:w-auto">
                            <div className="flex items-center gap-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Status</label>
                                <select 
                                    value={selectedTicket.status}
                                    onChange={(e) => handleStatusChange(e.target.value)}
                                    className="text-xs border border-gray-300 rounded-lg px-2 py-1.5 bg-white font-medium outline-none focus:ring-2 focus:ring-blue-500 w-full md:w-auto"
                                >
                                    <option value="Open">Open</option>
                                    <option value="In Progress">In Progress</option>
                                    <option value="Resolved">Resolved</option>
                                    <option value="Closed">Closed</option>
                                </select>
                            </div>

                            {/* SuperAdmin Reassignment Tool */}
                            {isSuperAdmin && (
                                <div className="flex items-center gap-2 mt-1 pt-2 border-t border-slate-200">
                                    <select
                                        className="text-xs border border-gray-300 rounded-lg px-2 py-1.5 bg-white font-medium outline-none focus:ring-2 focus:ring-indigo-500 w-full"
                                        value={assignAgent}
                                        onChange={(e) => setAssignAgent(e.target.value)}
                                    >
                                        <option value="">Reassign Agent...</option>
                                        {validationLists?.inspectors.map(name => (
                                            <option key={name} value={name}>{name}</option>
                                        ))}
                                    </select>
                                    <button 
                                        onClick={handleReassign}
                                        disabled={isAssigning || !assignAgent}
                                        className="bg-indigo-600 text-white p-1.5 rounded-lg disabled:opacity-50"
                                        title="Assign"
                                    >
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {/* Content - Scrollable */}
                <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 bg-slate-50/50">
                    {/* Original Request */}
                    <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm">
                        <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                                <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center text-[10px] font-bold text-slate-600">
                                    {selectedTicket.user.charAt(0)}
                                </div>
                                <span className="text-sm font-bold text-gray-700">{selectedTicket.user}</span>
                                <span className="text-[10px] text-gray-400">{new Date(selectedTicket.timestamp).toLocaleString()}</span>
                            </div>
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400">Original Request</span>
                        </div>
                        <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{selectedTicket.description}</p>
                    </div>

                    {/* Timeline / Comments */}
                    {selectedTicket.comments?.map((comment, idx) => {
                        const isMe = comment.user === currentUser?.name;
                        const isAdminComment = comment.role === 'Admin' || comment.role === 'SuperAdmin';

                        return (
                            <div key={idx} className={`flex gap-3 ${isMe ? 'flex-row-reverse' : ''}`}>
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-sm shrink-0 mt-1
                                    ${isAdminComment ? 'bg-indigo-600' : 'bg-slate-400'}`}>
                                    {isAdminComment ? 'SP' : comment.user.charAt(0)}
                                </div>
                                <div className={`max-w-[85%] md:max-w-[70%] rounded-2xl p-4 shadow-sm text-sm ${
                                    isMe 
                                        ? 'bg-blue-600 text-white rounded-tr-none' 
                                        : 'bg-white border border-gray-100 text-gray-700 rounded-tl-none'
                                }`}>
                                    <div className={`text-[10px] font-bold mb-1 opacity-70 ${isMe ? 'text-blue-100' : 'text-gray-400'}`}>
                                        {comment.user} • {new Date(comment.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                    </div>
                                    <p className="leading-relaxed break-words">{comment.message}</p>
                                </div>
                            </div>
                        );
                    })}
                    <div ref={messagesEndRef} />
                </div>

                {/* Reply Box - Rigid Footer */}
                <div className="p-4 bg-white border-t border-gray-200 shrink-0">
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            className="flex-1 border border-gray-300 rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-indigo-500 transition"
                            placeholder="Type a reply..."
                            value={replyText}
                            onChange={(e) => setReplyText(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleReply()}
                        />
                        <button 
                            onClick={handleReply}
                            disabled={isSendingReply || !replyText.trim()}
                            className="bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl px-6 py-2 font-bold transition disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {isSendingReply ? '...' : 'Send'}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fadeIn pb-12">
            <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-3">
                        <div className="w-10 h-10 rounded-lg bg-indigo-600 text-white flex items-center justify-center shadow-lg">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
                        </div>
                        Help & Support Hub
                    </h2>
                    <p className="text-gray-500 text-sm mt-1 ml-14">Get assistance, track tickets, or share the system.</p>
                </div>

                {/* Mode Toggle */}
                <div className="bg-white p-1 rounded-lg border border-gray-200 shadow-sm flex">
                    <button 
                        onClick={() => { setActiveTab('create'); setSelectedTicket(null); }}
                        className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'create' ? 'bg-indigo-50 text-indigo-700' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        New Request
                    </button>
                    <button 
                        onClick={() => { setActiveTab('list'); fetchTickets(); }}
                        className={`px-4 py-2 rounded-md text-xs font-bold transition-all relative ${activeTab === 'list' ? 'bg-indigo-50 text-indigo-700' : 'text-gray-500 hover:bg-gray-50'}`}
                    >
                        My Tickets
                        {activeTicketCount > 0 && (
